export type SimplicityDelta = {
  lineCountBefore: number;
  lineCountAfter: number;
  fileCountBefore: number;
  fileCountAfter: number;
  linesDelta: number;
  filesDelta: number;
  simpler: boolean;
};

type Health = {
  generationId: string;
  healthy: boolean;
  whoIAmAccordingToB: string;
  notes: string;
  reportedAt: string;
};

type SwapPending = {
  generationId: string;
  imageTag: string;
  previousTag: string;
  declaredAt: string;
  reason: string;
};

